<?php $labels=['pending_whatsapp'=>'Baru','confirmed'=>'Dikonfirmasi','completed'=>'Selesai','cancelled'=>'Dibatalkan'];?><header class="page-head"><div><span class="eyebrow">Hari ini</span><h1>Ringkasan toko</h1></div><a class="button" href="<?=url('/admin/products/create')?>">Tambah produk</a></header><section class="stat-grid"><article><span>Produk aktif</span><strong><?=$stats['products']?></strong></article><article><span>Stok rendah</span><strong><?=$stats['low']?></strong></article><article><span>Pesanan baru</span><strong><?=$stats['orders']?></strong></article><article><span>Nilai persediaan</span><strong><?=money($stats['value'])?></strong></article></section><section class="panel"><h2>Pesanan terbaru</h2><div class="table-wrap" tabindex="0" aria-label="Pesanan terbaru, geser horizontal bila diperlukan"><table><thead><tr><th>Nomor</th><th>Pelanggan</th><th>Total</th><th>Status</th></tr></thead><tbody><?php foreach($recent as $item):?><tr><td><?=e($item['order_number'])?></td><td><?=e($item['customer_name'])?></td><td><?=money($item['grand_total'])?></td><td><span class="badge"><?=e($labels[$item['status']]??$item['status'])?></span></td></tr><?php endforeach?><?php if(!$recent):?><tr><td colspan="4" class="empty-cell">Belum ada pesanan. Pesanan checkout WhatsApp akan muncul di sini.</td></tr><?php endif?></tbody></table></div></section>
